/**
 * Helpers
 */

export type OutfitId = "metal-light" | "inmate-timeout" | "futuristic" | "gimp-red" | "latex-pillar" | "azer-doll" | "fuck-worm"
    | "latex-toy-deluxe" | "latex-toy-trial" | "al-drone-pro1" | "metal-clothed" | "pet-naked" | "pet-clothed";

// Info on Outfit
export type OutfitTag = "harsh" | "use_echo" | "isolation" | "can_randomize" | "doll" | "pet" | "custom_color";

export function getOutfitSettingsFromId(setting: OutfitsSettings, id: OutfitId): SingleOutfitSetting {
    switch (id) {
        case "metal-light":
            return setting.metalOutfit;
        case "inmate-timeout":
            return setting.inmateTimeOut;
        case "futuristic":
            return setting.futuristicOutfit;
        case "gimp-red":
            return setting.gimpRed;
        case "latex-pillar":
            return setting.latexPillar;
        case "azer-doll":
            return setting.azerDoll;
        case "fuck-worm":
            return setting.fuckWorm;
        case "latex-toy-deluxe":
            return setting.latexToyDeluxe;
        case "latex-toy-trial":
            return setting.latexToyTrial;
        case "al-drone-pro1":
            return setting.alDronePro1;
        case "metal-clothed":
            return setting.metalClothed;
        case "pet-naked":
            return setting.petNaked;
        case "pet-clothed":
            return setting.petClothed;
    }
}
export function getRawOutfitFromId(id: string): RawOutfit | undefined {
    for (let i = 0; i < allOutfitList.length; i++) {
        if (allOutfitList[i].id == id) {
            return allOutfitList[i];
        }
    }
    return undefined;
}
export function getOutfitIdFromName(name: string): OutfitId | undefined {
    for (let i = 0; i < allOutfitList.length; i++) {
        if (allOutfitList[i].name == name) {
            return allOutfitList[i].id;
        }
    }
    return undefined;
}

export function extractOutfitDataFromId(outfitId: OutfitId): ItemBundle[] {
    if (outfitId) {
        const rawOutfit = getRawOutfitFromId(outfitId);
        if (rawOutfit) {
            return extractOutfitDataFromCode(rawOutfit.code);
        }
    }
    return [];
}

export function extractOutfitDataFromCode(outfitCode: string): ItemBundle[] {
    const parsed = LZString.decompressFromBase64(outfitCode);
    if (parsed) {
        const parsedData = JSON.parse(parsed);
        return parsedData as ItemBundle[];
    }
    return [];
}

